INSERT INTO `book_page` (`id`, `book_id`, `page_no`, `title`, `content_type`, `content_text_ko`, `content_text_en`, `image_url`, `created_at`, `updated_at`) VALUES
(1829, 151, 1, '숲으로', 'POEM', NULL, NULL, 'https://picsum.photos/seed/page1829/800/600', '2026-01-25 01:41:00', '2026-01-29 01:41:00'),
(1830, 151, 2, '따뜻한 저녁', 'SCENE', '비가 그치자 무지개가 마을을 감쌌습니다. 구름 사이로 햇살이 비치자 모두가 미소지었습니다. 달빛 아래에서 두 친구는 오래도록 이야기를 나누었습니다.', 'Two old friends sat by the river and shared their stories. A soft breeze carried the smell of fresh bread through the street. A single candle lit the whole room with a warm glow.', NULL, '2026-01-25 01:41:00', '2026-01-29 01:41:00'),
(1831, 151, 3, '함께한 하루', 'SCENE', NULL, NULL, 'https://picsum.photos/seed/page1831/800/600', '2026-01-25 01:41:00', '2026-01-29 01:41:00'),
(1832, 151, 4, '첫 만남', 'PAGE', '함께라면 무엇이든 해낼 수 있을 것 같았습니다. 작은 발걸음이 모여 커다란 여행이 되었습니다. 숲속에서 들려오는 소리에 귀를 기울였습니다.', 'The lantern flickered as the wind grew stronger outside. The garden was full of flowers no one remembered planting. She held the letter close and read it one more time.', NULL, '2026-01-25 01:41:00', '2026-01-29 01:41:00'),
(1833, 151, 5, '돌아오는 길', 'CHAPTER', NULL, NULL, 'https://picsum.photos/seed/page1833/800/600', '2026-01-25 01:41:00', '2026-01-29 01:41:00'),
(1834, 151, 6, '첫 만남', 'POEM', '작은 실수도 함께 웃으며 넘길 수 있었습니다. 비가 그치자 무지개가 마을을 감쌌습니다. 달빛 아래에서 두 친구는 오래도록 이야기를 나누었습니다. 작은 발걸음이 모여 커다란 여행이 되었습니다.', 'The last page of the book was missing, and no one knew why. She found an old key hidden inside the wooden box.', NULL, '2026-01-25 01:41:00', '2026-01-29 01:41:00'),
(1835, 151, 7, '비 오는 날', 'PAGE', NULL, NULL, 'https://picsum.photos/seed/page1835/800/600', '2026-01-25 01:41:00', '2026-01-29 01:41:00'),
(1836, 151, 8, '비 오는 날', 'SCENE', '숲속에서 들려오는 소리에 귀를 기울였습니다. 새로운 친구를 만난 순간, 마음이 두근거렸습니다.', 'The children built a small boat out of paper and leaves. Deep in the forest, something rustled quietly among the leaves.', NULL, '2026-01-25 01:41:00', '2026-01-29 01:41:00'),
(1837, 152, 1, '돌아오는 길', 'POEM', NULL, NULL, 'https://picsum.photos/seed/page1837/800/600', '2026-06-30 14:50:00', '2026-07-02 14:50:00'),
(1838, 152, 2, '다시 만난 날', 'CHAPTER', '달빛 아래에서 두 친구는 오래도록 이야기를 나누었습니다. 비가 그치자 무지개가 마을을 감쌌습니다. 처음엔 무서웠지만 곧 용기를 내기로 했습니다. 작은 실수도 함께 웃으며 넘길 수 있었습니다.', 'Deep in the forest, something rustled quietly among the leaves. Every evening, the baker left a loaf of bread by the door. The fox watched them from behind a fallen tree. The little village woke up slowly under the morning light.', NULL, '2026-06-30 14:50:00', '2026-07-02 14:50:00'),
(1839, 152, 3, '다시 만난 날', 'POEM', NULL, NULL, 'https://picsum.photos/seed/page1839/800/600', '2026-06-30 14:50:00', '2026-07-02 14:50:00'),
(1840, 152, 4, '약속의 순간', 'SCENE', '작은 마을에 사는 아이는 매일 창밖을 바라보았습니다. 비가 그치자 무지개가 마을을 감쌌습니다. 달빛 아래에서 두 친구는 오래도록 이야기를 나누었습니다. 작은 발걸음이 모여 커다란 여행이 되었습니다.', 'The fox watched them from behind a fallen tree. Rain tapped gently on the roof while they slept. The old clock in the hallway had stopped ticking years ago. The children built a small boat out of paper and leaves.', NULL, '2026-06-30 14:50:00', '2026-07-02 14:50:00'),
(1841, 152, 5, '다시 만난 날', 'POEM', NULL, NULL, 'https://picsum.photos/seed/page1841/800/600', '2026-06-30 14:50:00', '2026-07-02 14:50:00'),
(1842, 153, 1, '다시 만난 날', 'SCENE', NULL, NULL, 'https://picsum.photos/seed/page1842/800/600', '2026-06-09 22:45:00', '2026-06-14 22:45:00'),
(1843, 153, 2, '함께한 하루', 'SCENE', '처음엔 무서웠지만 곧 용기를 내기로 했습니다. 작은 발걸음이 모여 커다란 여행이 되었습니다. 숲속에서 들려오는 소리에 귀를 기울였습니다. 구름 사이로 햇살이 비치자 모두가 미소지었습니다.', 'Every winter, the lake froze just enough to walk across. The old clock in the hallway had stopped ticking years ago.', NULL, '2026-06-09 22:45:00', '2026-06-14 22:45:00'),
(1844, 153, 3, '첫 만남', 'SCENE', NULL, NULL, 'https://picsum.photos/seed/page1844/800/600', '2026-06-09 22:45:00', '2026-06-14 22:45:00'),
(1845, 153, 4, '약속의 순간', 'POEM', '작은 실수도 함께 웃으며 넘길 수 있었습니다. 함께라면 무엇이든 해낼 수 있을 것 같았습니다.', 'The dog barked twice, then ran ahead down the path. The old clock in the hallway had stopped ticking years ago. Nobody expected the small boat to survive the storm. A single candle lit the whole room with a warm glow.', NULL, '2026-06-09 22:45:00', '2026-06-14 22:45:00'),
(1846, 153, 5, '첫 만남', 'PAGE', NULL, NULL, 'https://picsum.photos/seed/page1846/800/600', '2026-06-09 22:45:00', '2026-06-14 22:45:00'),
(1847, 154, 1, '작은 기적', 'POEM', NULL, NULL, 'https://picsum.photos/seed/page1847/800/600', '2026-04-01 13:49:00', '2026-04-03 13:49:00'),
(1848, 154, 2, '작은 결심', 'POEM', '새로운 친구를 만난 순간, 마음이 두근거렸습니다. 구름 사이로 햇살이 비치자 모두가 미소지었습니다. 숲속에서 들려오는 소리에 귀를 기울였습니다. 함께라면 무엇이든 해낼 수 있을 것 같았습니다.', 'The mountain path was steep, but the view was worth it. He took a deep breath and stepped through the old gate.', NULL, '2026-04-01 13:49:00', '2026-04-03 13:49:00'),
(1849, 154, 3, '함께한 하루', 'SCENE', NULL, NULL, 'https://picsum.photos/seed/page1849/800/600', '2026-04-01 13:49:00', '2026-04-03 13:49:00'),
(1850, 154, 4, '다시 만난 날', 'POEM', '새로운 친구를 만난 순간, 마음이 두근거렸습니다. 구름 사이로 햇살이 비치자 모두가 미소지었습니다. 달빛 아래에서 두 친구는 오래도록 이야기를 나누었습니다.', 'The children built a small boat out of paper and leaves. A warm cup of tea waited for him on the table. Deep in the forest, something rustled quietly among the leaves.', NULL, '2026-04-01 13:49:00', '2026-04-03 13:49:00'),
(1851, 154, 5, '돌아오는 길', 'SCENE', NULL, NULL, 'https://picsum.photos/seed/page1851/800/600', '2026-04-01 13:49:00', '2026-04-03 13:49:00'),
